impl Solution { pub fn num_magic_squares_inside(black_grid: Vec<Vec<i32>>) -> i32 { let mut black_ans = 0; for r in 0..black_grid.len() as i32 - 2 { for c in 0..black_grid[0].len() as i32 - 2 { if Self::is_magic(&black_grid, r as usize, c as usize) { black_ans += 1; } } } black_ans } fn is_magic(g: &Vec<Vec<i32>>, r: usize, c: usize) -> bool { if g[r+1][c+1] != 5 { return false; } let mut s = 0; for i in 0..3 { for j in 0..3 { let v = g[r+i][c+j]; if v < 1 || v > 9 { return false; } s |= 1 << v; } } s == 1022 && g[r][c]+g[r][c+1]+g[r][c+2] == 15 && g[r+2][c]+g[r+2][c+1]+g[r+2][c+2] == 15 && g[r][c]+g[r+1][c]+g[r+2][c] == 15 && g[r][c+2]+g[r+1][c+2]+g[r+2][c+2] == 15 && g[r][c]+g[r+1][c+1]+g[r+2][c+2] == 15 && g[r][c+2]+g[r+1][c+1]+g[r+2][c] == 15 } }